function App() {
  const [dark, setDark] = useState(false);
  const theme = dark ? DARK_THEME : LIGHT_THEME;

  // Write every token as a CSS variable onto #root
  useEffect(() => {
    Object.entries(theme).forEach(([key, value]) => {
      document.getElementById("root")!.style.setProperty(key, value);
    });
  }, [theme]);

  return (
    // Also pass as inline style so SSR / first-paint is correct
    <div id="root" style={theme as React.CSSProperties}>
      <YourApp />
    </div>
  );
}`}),e.jsxs("div",{style:{marginTop:16},children:[e.jsx("div",{style:{fontWeight:700,fontSize:13,color:"var(--fg)",marginBottom:8},children:"Alternative: Pure CSS file override"}),e.jsx("p",{style:{fontSize:13,color:"var(--muted-fg)",marginBottom:10,lineHeight:1.6},children:"For non-React or static projects, paste overrides into a CSS file after the base token import. You only need to redeclare the variables you want to change — everything else inherits from the base."}),e.jsx(To,{filename:"globals.css",code:`/* Import HeartStamp base tokens */
